ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  customerId: payload[0].customer_id,
  accountNumber: payload[0].account_number,
  firstName: payload[0].first_name,
  lastName: payload[0].last_name,
  email: payload[0].email,
  phone: payload[0].phone,
  serviceAddress: {
    street: payload[0].service_street,
    city: payload[0].service_city,
    state: payload[0].service_state,
    zipCode: payload[0].service_zip,
    coordinates: {
      latitude: payload[0].service_latitude,
      longitude: payload[0].service_longitude
    }
  },
  energyProfile: {
    averageMonthlyUsage: payload[0].avg_monthly_usage,
    peakUsageHours: payload[0].peak_usage_hours splitBy ",",
    seasonalPattern: payload[0].seasonal_pattern
  }
}

ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
{
  startDate: (vars.period match {
    case "current" -> now() - |P1M|
    case "last30days" -> now() - |P30D|
    case "last90days" -> now() - |P90D|
    case "lastyear" -> now() - |P1Y|
    else -> now() - |P1M|
  }) as String {format: "yyyy-MM-dd"},
  endDate: now() as String {format: "yyyy-MM-dd"}
}

db:select.db:input-parameters:
#[{
        customerId: attributes.uriParams.customerId,
        startDate: vars.dateRange.startDate,
        endDate: vars.dateRange.endDate
      }]

#[{
            customerId: attributes.uriParams.customerId,
            startDate: vars.dateRange.startDate,
            endDate: vars.dateRange.endDate,
            prevStartDate: (vars.dateRange.startDate as Date - |P1M|) as String {format: "yyyy-MM-dd"},
            prevEndDate: (vars.dateRange.endDate as Date - |P1M|) as String {format: "yyyy-MM-dd"}
          }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  customerId: attributes.uriParams.customerId,
  period: {
    startDate: vars.dateRange.startDate as Date,
    endDate: vars.dateRange.endDate as Date
  },
  usage: {
    totalKwh: payload[0].total_kwh default 0,
    dailyAverage: payload[0].daily_average default 0,
    peakDemand: max(payload.peak_demand default [0]),
    offPeakUsage: sum(payload.off_peak_usage default [0]),
    costPerKwh: avg(payload.cost_per_kwh default [0])
  },
  (comparison: {
    previousPeriod: vars.comparisonData[0].previous_period_total default 0,
    neighborhoodAverage: vars.comparisonData[0].neighborhood_avg default 0,
    similarHomes: vars.comparisonData[0].similar_homes_avg default 0
  }) if vars.includeComparison
}

db:select.db:input-parameters:
#[{
        customerId: attributes.uriParams.customerId,
        startDate: vars.startDate,
        endDate: vars.endDate
      }]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  customerId: attributes.uriParams.customerId,
  (currentBill: {
    billId: vars.currentBill[0].bill_id,
    amount: vars.currentBill[0].amount,
    dueDate: vars.currentBill[0].due_date as Date,
    periodStart: vars.currentBill[0].period_start as Date,
    periodEnd: vars.currentBill[0].period_end as Date,
    status: vars.currentBill[0].status,
    breakdown: {
      energyCharges: vars.currentBill[0].energy_charges,
      deliveryCharges: vars.currentBill[0].delivery_charges,
      taxes: vars.currentBill[0].taxes,
      fees: vars.currentBill[0].fees
    }
  }) if sizeOf(vars.currentBill) > 0,
  paymentHistory: payload map {
    billId: $.bill_id,
    amount: $.amount,
    paymentDate: $.payment_date as Date,
    method: $.payment_method
  }
}

%dw 2.0
output application/json
---
{
  message: "Payment plan created successfully",
  planId: vars.planId,
  customerId: attributes.uriParams.customerId,
  setupDate: now() as String {format: "yyyy-MM-dd"}
}
